update public.case_studies
set
  status = 'published',
  featured = false,
  "order" = 3,
  title = 'Flock Accessibility Audit & Design System Unification',
  company = 'Flock',
  client_context = 'Paychex via ITX Corp',
  role = 'Product Designer',
  year = 2025,
  duration = '6 months audit + 1 year build',
  industry = 'Accessibility / Design Systems',
  tagline = 'Led an accessibility audit and helped unify the design system. This reduced pattern debt, made the product more consistent, and improved collaboration between design and development teams.',
  tags = array['Accessibility','Design Systems','UX Research','Product Design','Axe','A11y','Design system','Voice Over','Storybook'],
  filters = array['Accessibility','Design Systems','Product Design'],
  tools = array['Figma','Jira','Miro'],
  images = '{"cover":"/images/projects/flock-accessibility-system/thumbnails/flock.png","hero":"/images/projects/flock-accessibility-system/hero/flock-hero.png","gallery":[]}'::jsonb,
  client_logos = '[]'::jsonb,
  metrics = '[{"value":"6 months","label":"Audit and prioritization","context":"initial accessibility and system review"},{"value":"1 system","label":"Shared foundation","context":"aligned patterns, typography, icons, and dialogs"}]'::jsonb,
  team = array['1 designer','UX Lead','UX Manager','Product Owner','Business Analyst','3 developers','Dev Lead'],
  my_role = array['Accessibility Audit Lead','Component Strategy','Design Systems','Engineering Partnership'],
  problem = '{"admin_pain_points":["The product had accessibility risk across core flows and no mature shared library to address issues systematically.","Teams were working with duplicated patterns, inconsistent naming, and fragmented component behavior across pages.","Weak documentation and handoff ambiguity created implementation friction and made system decisions harder to scale."],"user_pain_points":["Inconsistent components made the experience less predictable from page to page.","Accessibility gaps reduced clarity and usability for people relying on stronger hierarchy, focus treatment, and consistent interaction states.","Dialogs, icons, typography, and responsive behavior lacked enough shared rules to feel cohesive across the product."]}'::jsonb,
  constraints = array['Accessibility improvements had to happen while the product was live and already fragmented across multiple pages and patterns.','There was no fully mature design system in place, so audit work and system definition had to progress together.','The system needed to support real engineering constraints, QA, and implementation readiness rather than remain a Figma-only cleanup effort.'],
  methodology = '{"name":"Audit to Systemization","steps":[{"step":1,"label":"Audit","description":"Checked for accessibility issues and components that didn''t match the system."},{"step":2,"label":"Structure","description":"Grouped problems by importance to see what to fix first."},{"step":3,"label":"Systemize","description":"Created clear patterns, states, and rules for how components should work."},{"step":4,"label":"Align","description":"Worked with developers to make sure designs could be built correctly in React."},{"step":5,"label":"Validate","description":"Reviewed designs and builds, using feedback to improve consistency."}]}'::jsonb,
  design_strategy = array['Clarify foundations, components, patterns, and modules so teams know when to use each pattern and how it should behave.','Separated accessibility fixes from design-system decisions by documenting patterns, variants, states, and usage rules.','Worked closely with developers to adapt component decisions to implementation realities, QA needs, and handoff clarity.','Used design review, accessibility checks, and implementation feedback to strengthen adoption and consistency.'],
  reflections = '[{"title":"Usability is about revealing what matters.","body":"Usability isn''t about removing; it''s about revealing what matters. This project proves that accessibility, performance, and UX all strengthen each other when treated as one discipline."}]'::jsonb,
  content_blocks = $json$[
    {"id":"overview","type":"overview","title":"Overview","body":""},
    {"id":"team-context","type":"custom","title":"Team","body":"I led the audit framing, defined which patterns needed consolidation, and partnered with engineering on how components should behave in build. I worked alongside another designer, in collaboration with a UX Lead, UX Manager, Product Owner, Business Analyst, three developers, and a Dev Lead."},
    {"id":"situation","type":"custom","title":"Situation","body":"The lack of a design system meant icons, typography, dialogs, repeated interface patterns, inconsistent component behavior, and reusable UI patterns had drifted over time.\n\nThat created friction for implementation, affected accessibility readiness, made handoffs less reliable, and increased the cost of maintaining consistency in the experience."},
    {"id":"task","type":"custom","title":"Task","body":"My role was to turn accessibility findings and UI inconsistencies into a clear system direction to define reusable patterns that design and engineering could adopt.\n\nThe product had been recently acquired, so the goal was to keep its visual identity while improving consistency and usability through a more scalable, React-based system.\n\nSuccess meant reducing duplicated patterns, improving the product, clarifying handoff expectations, and creating stronger accessibility guidance for future work."},
    {"id":"actions","type":"custom","title":"Actions","payload":{"items":["I built an audit framework that grouped issues by severity, system impact, and implementation complexity, while separating accessibility findings, system inconsistencies, and engineering constraints for clearer decision-making.","I reviewed foundations and shared patterns across icons, typography, dialogs, and components to identify where states, variants, naming, and responsive behavior needed to be standardized. From that, I defined reusable patterns and clearer guidance in Figma to reduce ambiguity and improve handoff consistency.","I also partnered closely with developers during review and QA to adapt patterns to real technical constraints and confirm that the proposed system decisions worked in build."]}},
    {"id":"impact","type":"results","title":"Product/System Outcomes","body":"The project created a clearer system foundation for accessibility, component reuse, and implementation consistency. Because confirmed business metrics were not preserved, the outcomes are framed through product, system, and delivery signals.","payload":{"rows":[{"metric":"Accessibility risk","value":"Lowered"},{"metric":"Pattern debt","value":"Reduced"},{"metric":"Handoff clarity","value":"Stronger"}],"insights":["The audit made severity and prioritization visible, which helped the team address structural accessibility problems instead of isolated UI fixes.","Shared guidance for icons, typography, dialogs, and reusable patterns reduced inconsistency and gave the system a clearer source of truth.","Defining states, variants, and usage rules reduced ambiguity between design and engineering and improved the quality of implementation conversations."],"projected":["A clearer adoption path for reusable components, patterns, and modules.","More reliable handoff and QA because accessibility notes and usage guidance are documented.","Lower risk in future accessibility reviews by addressing issues systemically instead of page by page.","Pattern consistency helps users understand the interactions on the pages."],"successMetrics":["Reduction of duplicated or conflicting component patterns.","Improved components’ states, variants, and responsive behavior across reused modules.","Fewer implementation questions during handoff and QA.","Accessibility issues identified and resolved by severity before release."]}}
  ]$json$::jsonb,
  nda_notice = null,
  password = null,
  external_link = null
where slug = 'flock-accessibility-system';
